SELECT emotion
  FROM diary_emotion
 WHERE diary_id = #{diary_id}

SELECT f.id AS forest_id , f.name AS forest_name , f.is_public , f.background_id AS background_id , f.user_id , b.image_url AS background_image_url
, p.id AS placement_id , p.position_x AS placement_position_x , p.position_y AS placement_position_y , ui.id AS user_item_id , ui.placed_count
, i.id AS item_id , i.name AS item_name , i.image_url AS item_image_url FROM forest f LEFT JOIN background b ON f.background_id = b.id LEFT JOIN user_item ui ON ui.forest_id = f.id LEFT JOIN placement p ON p.user_item_id = ui.id LEFT JOIN item i ON ui.item_id = i.id WHERE f.id = #{forestId}
